The reference solution of that problem in Javascript is 
function solve(n, edges, k) {
    function countComponents(t) {
        const adj = new Array(n);
        for (let i = 0; i < n; i++) {
            adj[i] = [];
        }
        for (const [u, v, time] of edges) {
            if (time > t) {
                adj[u].push(v);
                adj[v].push(u);
            }
        }
        const visited = new Array(n).fill(false);
        let count = 0;
        for (let i = 0; i < n; i++) {
            if (!visited[i]) {
                count++;
                const queue = [i];
                visited[i] = true;
                while (queue.length > 0) {
                    const node = queue.shift();
                    for (const neighbor of adj[node]) {
                        if (!visited[neighbor]) {
                            visited[neighbor] = true;
                            queue.push(neighbor);
                        }
                    }
                }
            }
        }
        return count;
    }

    edges.sort((a, b) => a[2] - b[2]);
    let maxTime = edges.length > 0 ? edges[edges.length - 1][2] : 0;
    let low = 0, high = maxTime, answer = maxTime;
    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const count = countComponents(mid);
        if (count >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}

