fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    if (k == 1L) return 0L
    edges.sortWith(compareBy { it[2] })
    val maxTime = if (edges.isEmpty()) 0L else edges.last()[2]
    var low = 0L
    var high = maxTime
    var answer = maxTime
    fun countComponents(t: Long): Int {
        val adj = Array(n.toInt()) { mutableListOf<Long>() }
        for (edge in edges) {
            val u = edge[0]
            val v = edge[1]
            val time = edge[2]
            if (time > t) {
                adj[u.toInt()].add(v)
                adj[v.toInt()].add(u)
            }
        }
        val visited = BooleanArray(n.toInt())
        var count = 0
        for (i in 0 until n.toInt()) {
            if (!visited[i]) {
                count++
                val queue = LinkedList<Long>()
                queue.add(i.toLong())
                visited[i] = true
                while (queue.isNotEmpty()) {
                    val node = queue.removeFirst()
                    for (neighbor in adj[node.toInt()]) {
                        if (!visited[neighbor]) {
                            visited[neighbor] = true
                            queue.add(neighbor)
                        }
                    }
                }
            }
        }
        return count
    }
    while (low <= high) {
        val mid = (low + high) / 2
        val count = countComponents(mid)
        if (count >= k) {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    return answer
}
