                count++;
                const queue = [i];
                visited[i] = true;
                while (queue.length > 0) {
                    const node = queue.shift();
                    for (const neighbor of adj[node]) {
                        if (!visited[neighbor]) {
                            visited[neighbor] = true;
                            queue.push(neighbor);
                        }
                    }
                }
            }
        }
        return count;
