import java.util.*

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    val sortedEdges = edges.sortedWith(compareBy { it[2] })
    val maxTime = if (edges.isNotEmpty()) sortedEdges[sortedEdges.size - 1][2] else 0L
    var low = 0L
    var high = maxTime
    var answer = high

    fun countComponents(t: Long): Int {
        val adj = Array(n.toInt()) { mutableListOf<Long>() }
        for (edge in sortedEdges) {
            val u = edge[0]
            val v = edge[1]
            val time = edge[2]
            if (time > t) {
                adj[u.toInt()].add(v)
                adj[v.toInt()].add(u)
            }
        }
        val visited = BooleanArray(n.toInt())
        var count = 0
        for (i in 0 until n.toInt()) {
            if (!visited[i]) {
                count++
                val queue = ArrayDeque<Long>()
                queue.add(i.toLong())
                visited[i] = true
                while (queue.isNotEmpty()) {
                    val node = queue.removeFirst()
                    for (neighbor in adj[node.toInt()]) {
                        if (!visited[neighbor.toInt()]) {
                            visited[neighbor.toInt()] = true
                            queue.add(neighbor)
                        }
                    }
                }
            }
        }
        return count
    }

    while (low <= high) {
        val mid = (low + high) / 2
        val cnt = countComponents(mid)
        if (cnt >= k) {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    return answer
}
